void doubleIt(int n)
{
    n = n * 2; // only the local copy changes
}

int main()
{
    int x = 5;
    doubleIt(x);
    cout << x; // still 5!
}

void doubleIt(int &n) // note the &
{
    n = n * 2;
}

#include <iostream>

using namespace std;

void doubleIt(int &n)
{
    n = n * 2;
}

int main()
{
    int x = 5;

    doubleIt(x);

    cout << x << endl;

    return 0;
}

#include <iostream>

using namespace std;

void swapValues(int &a, int &b)
{
    int temp = a;
    a = b;
    b = temp;
}

int main()
{
    int x = 5;
    int y = 10;

    swapValues(x, y);

    cout << "x: " << x << ", y: " << y << endl;

    return 0;
}

